// Deep link configuration model
class DeepLinkConfig {
  final String scheme;
  final String host;
  final String path;
  final Map<String, String> queryParameters;
  final String? fragment;

  DeepLinkConfig({
    required this.scheme,
    required this.host,
    required this.path,
    this.queryParameters = const {},
    this.fragment,
  });

  factory DeepLinkConfig.fromUri(Uri uri) {
    return DeepLinkConfig(
      scheme: uri.scheme,
      host: uri.host,
      path: uri.path,
      queryParameters: uri.queryParameters,
      fragment: uri.fragment.isNotEmpty ? uri.fragment : null,
    );
  }

  String get fullPath => host.isNotEmpty ? '$host$path' : path;

  @override
  String toString() {
    return 'DeepLinkConfig(scheme: $scheme, host: $host, path: $path, '
        'queryParameters: $queryParameters, fragment: $fragment)';
  }
}

// Route definitions
class AppRoutes {
  static const String home = '/';
  static const String profile = '/profile';
  static const String payment = '/payment';
  static const String paymentConfirm = '/payment/confirm';
  static const String campaign = '/campaign';
  static const String notFound = '/not-found';
}

// Router for generating routes
class AppRouter {
  static Route<dynamic> generateRoute(RouteSettings settings) {
    final uri = Uri.tryParse(settings.name ?? '');
    final args = settings.arguments as Map<String, dynamic>? ?? {};

    switch (settings.name) {
      case AppRoutes.home:
        return MaterialPageRoute(builder: (_) => const HomePage());

      case AppRoutes.profile:
        final userId = args['userId'] as String? ?? 'unknown';
        final source = args['source'] as String? ?? 'direct';
        return MaterialPageRoute(
          builder: (_) => ProfilePage(userId: userId, source: source),
        );

      case AppRoutes.paymentConfirm:
        final transactionId = args['transactionId'] as String?;
        final amount = args['amount'] as String?;
        final currency = args['currency'] as String? ?? 'USD';
        final status = args['status'] as String? ?? 'pending';
        return MaterialPageRoute(
          builder: (_) => PaymentConfirmPage(
            transactionId: transactionId,
            amount: amount,
            currency: currency,
            status: status,
          ),
        );

      case AppRoutes.campaign:
        final campaignId = args['campaignId'] as String? ?? 'unknown';
        final medium = args['medium'] as String? ?? 'unknown';
        final content = args['content'] as String?;
        return MaterialPageRoute(
          builder: (_) => CampaignPage(
            campaignId: campaignId,
            medium: medium,
            content: content,
          ),
        );

      default:
        return MaterialPageRoute(
          builder: (_) => NotFoundPage(attemptedRoute: settings.name),
        );
    }
  }
}

// Deep link handler singleton
class DeepLinkHandler {
  static final GlobalKey<NavigatorState> navigatorKey =
      GlobalKey<NavigatorState>();

  static StreamSubscription? _linkSubscription;
  static bool _initialLinkHandled = false;

  // Initialize deep link handling
  static Future<void> initialize() async {
    // Handle initial link (app was launched via deep link)
    await _handleInitialLink();

    // Listen for incoming links while app is running
    _linkSubscription = uriLinkStream.listen(
      (Uri? uri) {
        if (uri != null) {
          _processDeepLink(uri);
        }
      },
      onError: (Object err) {
        debugPrint('Deep link stream error: $err');
      },
    );
  }

  static Future<void> _handleInitialLink() async {
    if (_initialLinkHandled) return;
    _initialLinkHandled = true;

    try {
      final initialUri = await getInitialUri();
      if (initialUri != null) {
        // Small delay to ensure navigator is ready
        await Future.delayed(const Duration(milliseconds: 500));
        _processDeepLink(initialUri);
      }
    } catch (e) {
      debugPrint('Error handling initial deep link: $e');
    }
  }

  static void _processDeepLink(Uri uri) {
    debugPrint('Processing deep link: $uri');

    final config = DeepLinkConfig.fromUri(uri);
    debugPrint('Parsed config: $config');

    final routeInfo = _resolveRoute(config);

    if (routeInfo != null) {
      _navigateTo(routeInfo['route'] as String,
          arguments: routeInfo['arguments'] as Map<String, dynamic>?);
    } else {
      _navigateTo(AppRoutes.notFound,
          arguments: {'attemptedRoute': uri.toString()});
    }
  }

  static Map<String, dynamic>? _resolveRoute(DeepLinkConfig config) {
    final fullPath = config.fullPath;
    final segments = fullPath.split('/').where((s) => s.isNotEmpty).toList();

    debugPrint('Resolving route for segments: $segments');

    if (segments.isEmpty) {
      return {'route': AppRoutes.home, 'arguments': <String, dynamic>{}};
    }

    switch (segments[0]) {
      // myapp://profile/123 or myapp://profile/123?source=push
      case 'profile':
        final userId = segments.length > 1 ? segments[1] : 'unknown';
        final source = config.queryParameters['source'] ?? 'deeplink';
        return {
          'route': AppRoutes.profile,
          'arguments': <String, dynamic>{
            'userId': userId,
            'source': source,
            ...config.queryParameters,
          },
        };

      // myapp://payment/confirm?transactionId=abc&amount=29.99&currency=USD&status=success
      case 'payment':
        if (segments.length > 1 && segments[1] == 'confirm') {
          return {
            'route': AppRoutes.paymentConfirm,
            'arguments': <String, dynamic>{
              'transactionId': config.queryParameters['transactionId'],
              'amount': config.queryParameters['amount'],
              'currency': config.queryParameters['currency'] ?? 'USD',
              'status': config.queryParameters['status'] ?? 'pending',
              ...config.queryParameters,
            },
          };
        }
        return null;

      // myapp://campaign/summer2024?medium=email&content=banner1
      case 'campaign':
        final campaignId = segments.length > 1 ? segments[1] : 'unknown';
        final medium = config.queryParameters['medium'] ?? 'unknown';
        final content = config.queryParameters['content'];
        return {
          'route': AppRoutes.campaign,
          'arguments': <String, dynamic>{
            'campaignId': campaignId,
            'medium': medium,
            'content': content,
            ...config.queryParameters,
          },
        };

      default:
        return null;
    }
  }

  static void _navigateTo(String route, {Map<String, dynamic>? arguments}) {
    final navigator = navigatorKey.currentState;
    if (navigator != null) {
      navigator.pushNamed(route, arguments: arguments);
    } else {
      debugPrint('Navigator not available. Queuing route: $route');
      // Retry after a short delay
      Future.delayed(const Duration(milliseconds: 300), () {
        final nav = navigatorKey.currentState;
        if (nav != null) {
          nav.pushNamed(route, arguments: arguments);
        }
      });
    }
  }

  // Simulate deep link for testing
  static void simulateDeepLink(String url) {
    final uri = Uri.parse(url);
    _processDeepLink(uri);
  }

  static void dispose() {
    _linkSubscription?.cancel();
    _linkSubscription = null;
  }
}

// Wrapper widget that initializes deep link handling
class DeepLinkWrapper extends StatefulWidget {
  const DeepLinkWrapper({super.key});

  @override
  State<DeepLinkWrapper> createState() => _DeepLinkWrapperState();
}

