  @override
  void initState() {
    super.initState();
    DeepLinkHandler.initialize();
  }

  @override
  void dispose() {
    DeepLinkHandler.dispose();
    super.dispose();
  }

  @override
  Widget build(BuildContext context) {
    return const HomePage();
  }
}

